#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=8e4+5;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	while(1) {
		int n,a[maxn],ans=0;
		cin>>n;
		if(!n) {
			return 0;
		}
		stack<int> sta;
		for(int i=1; i<=n; i++)
			cin>>a[i];
		a[n+1]=0;
		for(int i=1; i<=n+1; i++) {
			if(sta.empty()||a[sta.top()]<=a[i]) {
				sta.push(i);
			} else {
				int pos;
				while(!sta.empty()&&a[sta.top()]>a[i]) {
					pos=sta.top();
					sta.pop();
					int l=i-pos;
					ans=max(ans,l*a[pos]);
				}
				sta.push(pos);
				a[pos]=a[i];
			}
		}
		cout<<ans<<"\n";
	}
	return 0;
}
